            </div>
          </el-col>
          <el-col :span="6">
            <div class="info-item">
              <span class="info-label">下单时间</span>
              <span class="info-value">{{ order.createTime }}</span>
            </div>
          </el-col>
        </el-row>
        <el-row v-if="order.payTime" :gutter="24" style="margin-top: 12px">
          <el-col :span="6">
            <div class="info-item">
              <span class="info-label">支付方式</span>
              <span class="info-value">{{ payMethodLabel }}</span>
            </div>
          </el-col>
          <el-col :span="6">
            <div class="info-item">
              <span class="info-label">支付时间</span>
              <span class="info-value">{{ order.payTime }}</span>
            </div>
          </el-col>
        </el-row>
      </el-card>

      <!-- 商品明细 -->
      <el-card shadow="never" class="info-card">
        <div slot="header" class="card-header">
          <span class="card-title">商品明细</span>
        </div>
        <el-table :data="order.items" border stripe size="small" style="width: 100%">
          <el-table-column label="商品图片" width="90" align="center">
            <template slot-scope="scope">
              <el-image
                style="width: 60px; height: 60px; border-radius: 4px"
