              />
            </template>
          </el-table-column>
          <el-table-column prop="name" label="商品名称" min-width="200" />
          <el-table-column prop="spec" label="规格" width="120" align="center">
            <template slot-scope="scope">
              {{ scope.row.spec || '-' }}
            </template>
          </el-table-column>
          <el-table-column label="单价" width="110" align="right">
            <template slot-scope="scope">
              ¥{{ (scope.row.price || 0).toFixed(2) }}
            </template>
          </el-table-column>
          <el-table-column label="数量" width="80" align="center">
            <template slot-scope="scope">
              {{ scope.row.quantity }}{{ scope.row.unit || '件' }}
            </template>
          </el-table-column>
          <el-table-column label="小计" width="120" align="right">
            <template slot-scope="scope">
              <span class="subtotal">¥{{ ((scope.row.price || 0) * (scope.row.quantity || 0)).toFixed(2) }}</span>
            </template>
          </el-table-column>
        </el-table>
        <div class="price-summary">
          <div class="price-row">
            <span>商品金额</span>
            <span>¥{{ (order.goodsAmount || 0).toFixed(2) }}</span>
          </div>
          <div v-if="order.discountAmount" class="price-row discount">
            <span>优惠金额</span>
            <span>-¥{{ (order.discountAmount || 0).toFixed(2) }}</span>
          </div>
          <div v-if="order.shippingFee" class="price-row">
            <span>运费</span>
            <span>¥{{ (order.shippingFee || 0).toFixed(2) }}</span>
          </div>
          <div class="price-row total">
            <span>实付金额</span>
            <span>¥{{ (order.totalAmount || 0).toFixed(2) }}</span>
          </div>
        </div>
      </el-card>

      <!-- 收货地址 -->
      <el-card shadow="never" class="info-card">
        <div slot="header" class="card-header">
          <span class="card-title">收货地址</span>
        </div>
        <div class="address-block">
          <div class="address-line">
            <i class="el-icon-user-solid address-icon" />
            <span class="address-name">{{ order.receiverName }}</span>
            <span class="address-phone">{{ order.receiverPhone }}</span>
          </div>
          <div class="address-line address-detail">
            <i class="el-icon-location-outline address-icon" />
            <span>{{ order.receiverAddress }}</span>
          </div>
        </div>
      </el-card>

      <!-- 物流信息（已发货 / 已完成） -->
      <el-card v-if="order.status === 30 || order.status === 40" shadow="never" class="info-card">
        <div slot="header" class="card-header">
          <span class="card-title">物流信息</span>
        </div>
        <el-row :gutter="24">
          <el-col :span="8">
            <div class="info-item">
              <span class="info-label">快递公司</span>
              <span class="info-value">{{ shipCompanyLabel }}</span>
            </div>
          </el-col>
          <el-col :span="8">
            <div class="info-item">
              <span class="info-label">快递单号</span>
              <span class="info-value mono">{{ order.shipNo }}</span>
            </div>
          </el-col>
          <el-col :span="8">
            <div class="info-item">
              <span class="info-label">发货时间</span>
              <span class="info-value">{{ order.shipTime }}</span>
            </div>
          </el-col>
        </el-row>
        <div v-if="order.shipRemark" style="margin-top: 8px">
          <span class="info-label">备注：</span>
          <span class="info-value">{{ order.shipRemark }}</span>
        </div>
      </el-card>

      <!-- 订单时间轴 -->
      <el-card shadow="never" class="info-card">
        <div slot="header" class="card-header">
          <span class="card-title">订单进度</span>
        </div>
        <el-timeline class="order-timeline">
          <el-timeline-item
            v-for="(step, idx) in timelineSteps"
            :key="idx"
            :timestamp="step.time"
            :color="step.active ? '#9c6e21' : '#c0c4cc'"
            :icon="step.active ? 'el-icon-check' : 'el-icon-more-outline'"
            :type="step.active ? 'primary' : 'info'"
          >
            <span :class="{ 'timeline-text': true, 'timeline-active': step.active }">
              {{ step.title }}
            </span>
          </el-timeline-item>
        </el-timeline>
      </el-card>
    </div>

    <!-- 发货弹窗 -->
    <el-dialog
      title="订单发货"
      :visible.sync="shipDialogVisible"
      width="480px"
      :close-on-click-modal="false"
    >
      <el-form ref="shipForm" :model="shipForm" :rules="shipRules" label-width="90px" size="small">
        <el-form-item label="快递公司" prop="shipCompany">
          <el-select v-model="shipForm.shipCompany" placeholder="请选择快递公司" style="width: 100%">
            <el-option label="顺丰速运" value="SF" />
            <el-option label="中通快递" value="ZTO" />
            <el-option label="圆通速递" value="YTO" />
            <el-option label="韵达速递" value="YD" />
            <el-option label="申通快递" value="STO" />
            <el-option label="EMS" value="EMS" />
            <el-option label="极兔速递" value="JITU" />
            <el-option label="其他" value="OTHER" />
          </el-select>
        </el-form-item>
        <el-form-item label="快递单号" prop="shipNo">
          <el-input v-model="shipForm.shipNo" placeholder="请输入快递单号" />
        </el-form-item>
        <el-form-item label="备注">
          <el-input v-model="shipForm.remark" type="textarea" :rows="2" placeholder="选填" />
        </el-form-item>
      </el-form>
      <span slot="footer">
        <el-button size="small" @click="shipDialogVisible = false">取 消</el-button>
        <el-button size="small" type="primary" :loading="shipSubmitting" @click="confirmShip">
          确 认 发 货
        </el-button>
      </span>
    </el-dialog>
  </div>
</template>

<script>
import orderApi from '@/api/order'

/** 状态映射 */
const STATUS_MAP = {
  0: '已取消',
  10: '待付款',
  20: '待发货',
  30: '已发货',
  40: '已完成'
}

const STATUS_TAG_TYPE = {
  0: 'danger',
  10: 'info',
  20: 'warning',
  30: '',
  40: 'success'
}

/** 快递公司映射 */
const SHIP_COMPANY_MAP = {
  SF: '顺丰速运',
  ZTO: '中通快递',
  YTO: '圆通速递',
  YD: '韵达速递',
  STO: '申通快递',
  EMS: 'EMS',
  JITU: '极兔速递',
  OTHER: '其他'
}

/** 支付方式映射 */
const PAY_METHOD_MAP = {
  WECHAT: '微信支付',
  ALIPAY: '支付宝',
  BALANCE: '余额支付'
}

export default {
  name: 'OrderDetail',

  data() {
    return {
      orderId: null,
      loading: false,
      order: {
        orderNumber: '',
        createTime: '',
        status: 0,
        totalAmount: 0,
        payTime: '',
        paymentMethod: '',
        goodsAmount: 0,
        discountAmount: 0,
        shippingFee: 0,
        receiverName: '',
        receiverPhone: '',
        receiverAddress: '',
        shipCompany: '',
        shipNo: '',
        shipTime: '',
        shipRemark: '',
        items: [],
        logs: []
      },

      // 发货弹窗
      shipDialogVisible: false,
      shipForm: {
        shipCompany: '',
        shipNo: '',
        remark: ''
      },
      shipRules: {
        shipCompany: [{ required: true, message: '请选择快递公司', trigger: 'change' }],
        shipNo: [
          { required: true, message: '请输入快递单号', trigger: 'blur' },
          { min: 5, max: 50, message: '快递单号为 5~50 位', trigger: 'blur' }
        ]
      },
      shipSubmitting: false
    }
  },

  computed: {
    /** 状态文字 */
    statusLabel() {
      return STATUS_MAP[this.order.status] || '未知'
    },

    /** 状态标签类型 */
    statusTagType() {
      return STATUS_TAG_TYPE[this.order.status] || 'info'
    },

    /** 支付方式文字 */
    payMethodLabel() {
      return PAY_METHOD_MAP[this.order.paymentMethod] || this.order.paymentMethod || '-'
    },

    /** 快递公司文字 */
    shipCompanyLabel() {
      return SHIP_COMPANY_MAP[this.order.shipCompany] || this.order.shipCompany || '-'
    },

    /** 时间轴节点 */
    timelineSteps() {
      const steps = []
      const s = this.order.status
      const logs = this.order.logs || []

      // 辅助：从 logs 中按 action 找时间
      const logTime = (action) => {
        const found = logs.find((l) => l.action === action)
        return found ? found.createTime : ''
      }

      // 下单
      steps.push({
        title: '买家下单',
        time: this.order.createTime || logTime('CREATE'),
        active: true
      })

      // 付款
      const paid = s >= 20 && s !== 0
      steps.push({
        title: '买家付款',
        time: this.order.payTime || logTime('PAY'),
        active: paid
      })

      // 发货
      const shipped = s >= 30 && s !== 0
      steps.push({
        title: '商家发货',
        time: this.order.shipTime || logTime('SHIP'),
        active: shipped
      })

      // 完成
      const completed = s === 40
      steps.push({
        title: '订单完成',
        time: logTime('COMPLETE') || logTime('FINISH'),
        active: completed
      })

      return steps
    }
  },

  created() {
    this.orderId = this.$route.params.id
    if (!this.orderId) {
      this.$message.error('订单 ID 无效')
      this.$router.replace('/order/list')
      return
    }
    this.fetchDetail()
  },

  methods: {
    /** 获取订单详情 */
    async fetchDetail() {
      this.loading = true
      try {
        const res = await orderApi.getDetail(this.orderId)
        if (res.code === 0) {
          this.order = { ...this.order, ...(res.data || {}) }
        } else {
          this.$message.error(res.message || '获取详情失败')
        }
      } catch (err) {
        console.error('获取订单详情异常:', err)
      } finally {
        this.loading = false
      }
    },

    /** 取消订单 */
    handleCancel() {
      this.$confirm('确定要取消该订单吗？取消后无法恢复。', '取消确认', {
        type: 'warning'
      })
        .then(async () => {
          try {
            const res = await orderApi.updateStatus(this.orderId, { status: 0 })
            if (res.code === 0) {
              this.$message.success('订单已取消')
              this.order.status = 0
            } else {
              this.$message.error(res.message || '取消失败')
            }
          } catch (err) {
            console.error('取消异常:', err)
          }
        })
        .catch(() => {})
    },

    /** 发货 */
    handleShip() {
      this.shipForm = { shipCompany: '', shipNo: '', remark: '' }
      this.shipDialogVisible = true
      this.$nextTick(() => this.$refs.shipForm && this.$refs.shipForm.clearValidate())
    },

    /** 确认发货 */
    confirmShip() {
      this.$refs.shipForm.validate(async (valid) => {
        if (!valid) return
        this.shipSubmitting = true
        try {
          const res = await orderApi.ship(this.orderId, {
            shipCompany: this.shipForm.shipCompany,
            shipNo: this.shipForm.shipNo,
            remark: this.shipForm.remark
          })
          if (res.code === 0) {
            this.$message.success('发货成功')
            this.shipDialogVisible = false
            this.fetchDetail()
          } else {
            this.$message.error(res.message || '发货失败')
          }
        } catch (err) {
          console.error('发货异常:', err)
        } finally {
          this.shipSubmitting = false
        }
      })
    },

    /** 完成订单 */
    handleComplete() {
      this.$confirm('确认将该订单标记为已完成吗？', '完成确认', { type: 'info' })
        .then(async () => {
          try {
            const res = await orderApi.updateStatus(this.orderId, { status: 40 })
            if (res.code === 0) {
              this.$message.success('订单已完成')
              this.order.status = 40
            } else {
              this.$message.error(res.message || '操作失败')
            }
          } catch (err) {
            console.error('完成异常:', err)
          }
        })
        .catch(() => {})
    }
  }
}
</script>

